#include "biblia.h"

void Biblia::CarregarEclesiastes(Biblia* b) {
    b->dados[ECLESIASTES].nome = _("Eclesiastes");

    b->dados[ECLESIASTES].capitulos[1].versos[1] = _("Palavras do pregador, filho de Davi, rei em Jerusalém.");
    b->dados[ECLESIASTES].capitulos[1].versos[2] = _("Vaidade de vaidades, diz o pregador; vaidade de vaidades, tudo é vaidade.");
    b->dados[ECLESIASTES].capitulos[1].versos[3] = _("Que proveito tem o homem, de todo o seu trabalho, com que se afadiga debaixo do sol?");
    b->dados[ECLESIASTES].capitulos[1].versos[4] = _("Uma geração vai-se, e outra geração vem, mas a terra permanece para sempre.");
    b->dados[ECLESIASTES].capitulos[1].versos[5] = _("O sol nasce, e o sol se põe, e corre de volta ao seu lugar donde nasce.");
    b->dados[ECLESIASTES].capitulos[1].versos[6] = _("O vento vai para o sul, e faz o seu giro vai para o norte; volve-se e revolve-se na sua carreira, e retoma os seus circuitos.");
    b->dados[ECLESIASTES].capitulos[1].versos[7] = _("Todos os ribeiros vão para o mar, e contudo o mar não se enche; ao lugar para onde os rios correm, para ali continuam a correr.");
    b->dados[ECLESIASTES].capitulos[1].versos[8] = _("Todas as coisas estão cheias de cansaço; ninguém o pode exprimir: os olhos não se fartam de ver, nem os ouvidos se enchem de ouvir.");
    b->dados[ECLESIASTES].capitulos[1].versos[9] = _("O que tem sido, isso é o que há de ser; e o que se tem feito, isso se tornará a fazer; nada há que seja novo debaixo do sol.");
    b->dados[ECLESIASTES].capitulos[1].versos[10] = _("Há alguma coisa de que se possa dizer: Voê, isto é novo? ela já existiu nos séculos que foram antes de nós.");
    b->dados[ECLESIASTES].capitulos[1].versos[11] = _("Já não há lembrança das gerações passadas; nem das gerações futuras haverá lembrança entre os que virão depois delas.");
    b->dados[ECLESIASTES].capitulos[1].versos[12] = _("Eu, o pregador, fui rei sobre Israel em Jerusalém.");
    b->dados[ECLESIASTES].capitulos[1].versos[13] = _("E apliquei o meu coração a inquirir e a investigar com sabedoria a respeito de tudo quanto se faz debaixo do céu; essa enfadonha ocupação deu Deus aos filhos dos homens para nela se exercitarem.");
    b->dados[ECLESIASTES].capitulos[1].versos[14] = _("Atentei para todas as obras que se e fazem debaixo do sol; e eis que tudo era vaidade e desejo vão.");
    b->dados[ECLESIASTES].capitulos[1].versos[15] = _("O que é torto não se pode endireitar; o que falta não se pode enumerar.");
    b->dados[ECLESIASTES].capitulos[1].versos[16] = _("Falei comigo mesmo, dizendo: Eis que eu me engrandeci, e sobrepujei em sabedoria a todos os que houve antes de mim em Jerusalém; na verdade, tenho tido larga experiência da sabedoria e do conhecimento.");
    b->dados[ECLESIASTES].capitulos[1].versos[17] = _("E apliquei o coração a conhecer a sabedoria e a conhecer os desvarios e as loucuras; e vim a saber que também isso era desejo vão.");
    b->dados[ECLESIASTES].capitulos[1].versos[18] = _("Porque na muita sabedoria há muito enfado; e o que aumenta o conhecimento aumenta a tristeza.");

    b->dados[ECLESIASTES].capitulos[2].versos[1] = _("Disse eu a mim mesmo: Ora vem, eu te provarei com a alegria; portanto goza o prazer; mas eis que também isso era vaidade.");
    b->dados[ECLESIASTES].capitulos[2].versos[2] = _("Do riso disse: Está doido; e da alegria: De que serve estar.");
    b->dados[ECLESIASTES].capitulos[2].versos[3] = _("Busquei no meu coração como estimular com vinho a minha carne, sem deixar de me guiar pela sabedoria, e como me apoderar da estultícia, até ver o que era bom que os filhos dos homens fizessem debaixo do céu, durante o número dos dias de sua vida.");
    b->dados[ECLESIASTES].capitulos[2].versos[4] = _("Fiz para mim obras magníficas: edifiquei casas, plantei vinhas;");
    b->dados[ECLESIASTES].capitulos[2].versos[5] = _("fiz hortas e jardins, e plantei neles árvores frutíferas de todas as espécies.");
    b->dados[ECLESIASTES].capitulos[2].versos[6] = _("Fiz tanques de águas, para deles regar o bosque em que reverdeciam as árvores.");
    b->dados[ECLESIASTES].capitulos[2].versos[7] = _("Comprei servos e servas, e tive servos nascidos em casa; também tive grandes possessões de gados e de rebanhos, mais do que todos os que houve antes de mim em Jerusalém.");
    b->dados[ECLESIASTES].capitulos[2].versos[8] = _("Ajuntei também para mim prata e ouro, e tesouros dos reis e das províncias; provi-me de cantores e cantoras, e das delícias dos filhos dos homens, concubinas em grande número.");
    b->dados[ECLESIASTES].capitulos[2].versos[9] = _("Assim me engrandeci, e me tornei mais rico do que todos os que houve antes de mim em Jerusalém; perseverou também comigo a minha sabedoria.");
    b->dados[ECLESIASTES].capitulos[2].versos[10] = _("E tudo quanto desejaram os meus olhos não lho neguei, nem privei o meu coração de alegria alguma; pois o meu coração se alegrou por todo o meu trabalho, e isso foi o meu proveito de todo o meu trabalho.");
    b->dados[ECLESIASTES].capitulos[2].versos[11] = _("Então olhei eu para todas as obras que as minhas mãos haviam feito, como também para o trabalho que eu aplicara em fazê-las; e eis que tudo era vaidade e desejo vão, e proveito nenhum havia debaixo do sol.");
    b->dados[ECLESIASTES].capitulos[2].versos[12] = _("Virei-me para contemplar a sabedoria, e a loucura, e a estultícia; pois que fará o homem que seguir ao rei? O mesmo que já se fez!");
    b->dados[ECLESIASTES].capitulos[2].versos[13] = _("Então vi eu que a sabedoria é mais excelente do que a estultícia, quanto a luz é mais excelente do que as trevas.");
    b->dados[ECLESIASTES].capitulos[2].versos[14] = _("Os olhos do sábio estão na sua cabeça, mas o louco anda em trevas; contudo percebi que a mesma coisa lhes sucede a ambos.");
    b->dados[ECLESIASTES].capitulos[2].versos[15] = _("Pelo que eu disse no meu coração: Como acontece ao estulto, assim me sucederá a mim; por que então busquei eu mais a sabedoria; Então respondi a mim mesmo que também isso era vaidade.");
    b->dados[ECLESIASTES].capitulos[2].versos[16] = _("Pois do sábio, bem como do estulto, a memória não durará para sempre; porquanto de tudo, nos dias futuros, total esquecimento haverá. E como morre o sábio, assim morre o estulto!");
    b->dados[ECLESIASTES].capitulos[2].versos[17] = _("Pelo que aborreci a vida, porque a obra que se faz debaixo do sol me era penosa; sim, tudo é vaidade e desejo vão.");
    b->dados[ECLESIASTES].capitulos[2].versos[18] = _("Também eu aborreci todo o meu trabalho em que me afadigara debaixo do sol, visto que tenho de deixá-lo ao homem que virá depois de mim.");
    b->dados[ECLESIASTES].capitulos[2].versos[19] = _("E quem sabe se será sábio ou estulto? Contudo, ele se assenhoreará de todo o meu trabalho em que me afadiguei, e em que me houve sabiamente debaixo do sol; também isso é vaidade.");
    b->dados[ECLESIASTES].capitulos[2].versos[20] = _("Pelo que eu me volvi e entreguei o meu coração ao desespero no tocante a todo o trabalho em que me afadigara debaixo do sol.");
    b->dados[ECLESIASTES].capitulos[2].versos[21] = _("Porque há homem cujo trabalho é feito com sabedoria, e ciência, e destreza; contudo, deixará o fruto do seu labor para ser porção de quem não trabalhou nele; também isso é vaidade e um grande mal.");
    b->dados[ECLESIASTES].capitulos[2].versos[22] = _("Pois, que alcança o homem com todo o seu trabalho e com a fadiga em que ele anda trabalhando debaixo do sol?");
    b->dados[ECLESIASTES].capitulos[2].versos[23] = _("Porque todos os seus dias são dores, e o seu trabalho é vexação; nem de noite o seu coração descansa. Também isso é vaidade.");
    b->dados[ECLESIASTES].capitulos[2].versos[24] = _("Não há nada melhor para o homem do que comer e beber, e fazer que a sua alma goze do bem do seu trabalho. Vi que também isso vem da mão de Deus.");
    b->dados[ECLESIASTES].capitulos[2].versos[25] = _("Pois quem pode comer, ou quem pode gozar. melhor do que eu?");
    b->dados[ECLESIASTES].capitulos[2].versos[26] = _("Porque ao homem que lhe agrada, Deus dá sabedoria, e conhecimento, e alegria; mas ao pecador dá trabalho, para que ele ajunte e amontoe, a fim de dá-lo àquele que agrada a Deus: Também isso é vaidade e desejo vão.");

    b->dados[ECLESIASTES].capitulos[3].versos[1] = _("Tudo tem a sua ocasião própria, e há tempo para todo propósito debaixo do céu.");
    b->dados[ECLESIASTES].capitulos[3].versos[2] = _("Há tempo de nascer, e tempo de morrer; tempo de plantar, e tempo de arrancar o que se plantou;");
    b->dados[ECLESIASTES].capitulos[3].versos[3] = _("tempo de matar, e tempo de curar; tempo de derribar, e tempo de edificar;");
    b->dados[ECLESIASTES].capitulos[3].versos[4] = _("tempo de chorar, e tempo de rir; tempo de prantear, e tempo de dançar;");
    b->dados[ECLESIASTES].capitulos[3].versos[5] = _("tempo de espalhar pedras, e tempo de ajuntar pedras; tempo de abraçar, e tempo de abster-se de abraçar;");
    b->dados[ECLESIASTES].capitulos[3].versos[6] = _("tempo de buscar, e tempo de perder; tempo de guardar, e tempo de deitar fora;");
    b->dados[ECLESIASTES].capitulos[3].versos[7] = _("tempo de rasgar, e tempo de coser; tempo de estar calado, e tempo de falar;");
    b->dados[ECLESIASTES].capitulos[3].versos[8] = _("tempo de amar, e tempo de odiar; tempo de guerra, e tempo de paz.");
    b->dados[ECLESIASTES].capitulos[3].versos[9] = _("Que proveito tem o trabalhador naquilo em que trabalha?");
    b->dados[ECLESIASTES].capitulos[3].versos[10] = _("Tenho visto o trabalho penoso que Deus deu aos filhos dos homens para nele se exercitarem.");
    b->dados[ECLESIASTES].capitulos[3].versos[11] = _("Tudo fez formoso em seu tempo; também pôs na mente do homem a idéia da eternidade, se bem que este não possa descobrir a obra que Deus fez desde o princípio até o fim.");
    b->dados[ECLESIASTES].capitulos[3].versos[12] = _("Sei que não há coisa melhor para eles do que se regozijarem e fazerem o bem enquanto viverem;");
    b->dados[ECLESIASTES].capitulos[3].versos[13] = _("e também que todo homem coma e beba, e goze do bem de todo o seu trabalho é dom de Deus.");
    b->dados[ECLESIASTES].capitulos[3].versos[14] = _("Eu sei que tudo quanto Deus faz durará eternamente; nada se lhe pode acrescentar, e nada se lhe pode tirar; e isso Deus faz para que os homens temam diante dele:");
    b->dados[ECLESIASTES].capitulos[3].versos[15] = _("O que é, já existiu; e o que há de ser, também já existiu; e Deus procura de novo o que já se passou.");
    b->dados[ECLESIASTES].capitulos[3].versos[16] = _("Vi ainda debaixo do sol que no lugar da retidão estava a impiedade; e que no lugar da justiça estava a impiedade ainda.");
    b->dados[ECLESIASTES].capitulos[3].versos[17] = _("Eu disse no meu coração: Deus julgará o justo e o ímpio; porque há um tempo para todo propósito e para toda obra.");
    b->dados[ECLESIASTES].capitulos[3].versos[18] = _("Disse eu no meu coração: Isso é por causa dos filhos dos homens, para que Deus possa prová-los, e eles possam ver que são em si mesmos como os brutos.");
    b->dados[ECLESIASTES].capitulos[3].versos[19] = _("Pois o que sucede aos filhos dos homens, isso mesmo também sucede aos brutos; uma e a mesma coisa lhes sucede; como morre um, assim morre o outro; todos têm o mesmo fôlego; e o homem não tem vantagem sobre os brutos; porque tudo é vaidade.");
    b->dados[ECLESIASTES].capitulos[3].versos[20] = _("Todos vão para um lugar; todos são pó, e todos ao pó tornarão.");
    b->dados[ECLESIASTES].capitulos[3].versos[21] = _("Quem sabe se o espírito dos filhos dos homens vai para cima, e se o espírito dos brutos desce para a terra?");
    b->dados[ECLESIASTES].capitulos[3].versos[22] = _("Pelo que tenho visto que não há coisa melhor do que alegrar-se o homem nas suas obras; porque esse é o seu quinhão; pois quem o fará voltar para ver o que será depois dele?");

    b->dados[ECLESIASTES].capitulos[4].versos[1] = _("Depois volvi-me, e atentei para todas as opressões que se fazem debaixo do sol; e eis as lágrimas dos oprimidos, e eles não tinham consolador; do lado dos seus opressores havia poder; mas eles não tinham consolador.");
    b->dados[ECLESIASTES].capitulos[4].versos[2] = _("Pelo que julguei mais felizes os que já morreram, do que os que vivem ainda.");
    b->dados[ECLESIASTES].capitulos[4].versos[3] = _("E melhor do que uns e outros é aquele que ainda não é, e que não viu as más obras que se fazem debaixo do sol.");
    b->dados[ECLESIASTES].capitulos[4].versos[4] = _("Também vi eu que todo trabalho e toda destreza em obras provêm da inveja que o homem tem do seu próximo. Também isso é e vaidade e desejo vão.");
    b->dados[ECLESIASTES].capitulos[4].versos[5] = _("O tolo cruza as mãos, e come a sua; própria carne.");
    b->dados[ECLESIASTES].capitulos[4].versos[6] = _("Melhor é um punhado com tranqüilidade do que ambas as mãos cheias com trabalho e vão desejo.");
    b->dados[ECLESIASTES].capitulos[4].versos[7] = _("Outra vez me volvi, e vi vaidade debaixo do sol.");
    b->dados[ECLESIASTES].capitulos[4].versos[8] = _("Há um que é só, não tendo parente; não tem filho nem irmão e, contudo, de todo o seu trabalho não há fim, nem os seus olhos se fartam de riquezas. E ele não pergunta: Para quem estou trabalhando e privando do bem a minha alma? Também isso é vaidade a e enfadonha ocupação.");
    b->dados[ECLESIASTES].capitulos[4].versos[9] = _("Melhor é serem dois do que um, porque têm melhor paga do seu trabalho.");
    b->dados[ECLESIASTES].capitulos[4].versos[10] = _("Pois se caírem, um levantará o seu companheiro; mas ai do que estiver só, pois, caindo, não haverá outro que o levante.");
    b->dados[ECLESIASTES].capitulos[4].versos[11] = _("Também, se dois dormirem juntos, eles se aquentarão; mas um só como se aquentará?");
    b->dados[ECLESIASTES].capitulos[4].versos[12] = _("E, se alguém quiser prevalecer contra um, os dois lhe resistirão; e o cordão de três dobras não se quebra tão depressa.");
    b->dados[ECLESIASTES].capitulos[4].versos[13] = _("Melhor é o mancebo pobre e sábio do que o rei velho e insensato, que não se deixa mais admoestar,");
    b->dados[ECLESIASTES].capitulos[4].versos[14] = _("embora tenha saído do cárcere para reinar, ou tenha nascido pobre no seu próprio reino.");
    b->dados[ECLESIASTES].capitulos[4].versos[15] = _("Vi a todos os viventes que andavam debaixo do sol, e eles estavam com o mancebo, o sucessor, que havia de ficar no lugar do rei.");
    b->dados[ECLESIASTES].capitulos[4].versos[16] = _("Todo o povo, à testa do qual se achava, era inumerável; contudo os que lhe sucederam não se regozijarão a respeito dele. Na verdade também isso é vaidade e desejo vão.");

    b->dados[ECLESIASTES].capitulos[5].versos[1] = _("Guarda o teu pé, quando fores à casa de Deus; porque chegar-se para ouvir é melhor do que oferecer sacrifícios de tolos; pois não sabem que fazem mal.");
    b->dados[ECLESIASTES].capitulos[5].versos[2] = _("Não te precipites com a tua boca, nem o teu coração se apresse a pronunciar palavra alguma na presença de Deus; porque Deus está no céu, e tu estás sobre a terra; portanto sejam poucas as tuas palavras.");
    b->dados[ECLESIASTES].capitulos[5].versos[3] = _("Porque, da multidão de trabalhos vêm os sonhos, e da multidão de palavras, a voz do tolo.");
    b->dados[ECLESIASTES].capitulos[5].versos[4] = _("Quando a Deus fizeres algum voto, não tardes em cumpri-lo; porque não se agrada de tolos. O que votares, paga-o.");
    b->dados[ECLESIASTES].capitulos[5].versos[5] = _("Melhor é que não votes do que votares e não pagares.");
    b->dados[ECLESIASTES].capitulos[5].versos[6] = _("Não consintas que a tua boca faça pecar a tua carne, nem digas na presença do anjo que foi erro; por que razão se iraria Deus contra a tua voz, e destruiria a obra das tuas mãos?");
    b->dados[ECLESIASTES].capitulos[5].versos[7] = _("Porque na multidão dos sonhos há vaidades e muitas palavras; mas tu teme a Deus.");
    b->dados[ECLESIASTES].capitulos[5].versos[8] = _("Se vires em alguma província opressão de pobres, e a perversão violenta do direito e da justiça, não te maravilhes de semelhante caso. Pois quem está altamente colocado tem superior que o vigia; e há mais altos ainda sobre eles.");
    b->dados[ECLESIASTES].capitulos[5].versos[9] = _("O proveito da terra é para todos; até o rei se serve do campo.");
    b->dados[ECLESIASTES].capitulos[5].versos[10] = _("Quem ama o dinheiro não se fartará de dinheiro; nem o que ama a riqueza se fartará do ganho; também isso é vaidade.");
    b->dados[ECLESIASTES].capitulos[5].versos[11] = _("Quando se multiplicam os bens, multiplicam-se também os que comem; e que proveito tem o seu dono senão o de vê-los com os seus olhos?");
    b->dados[ECLESIASTES].capitulos[5].versos[12] = _("Doce é o sono do trabalhador, quer coma pouco quer muito; mas a saciedade do rico não o deixa dormir.");
    b->dados[ECLESIASTES].capitulos[5].versos[13] = _("Há um grave mal que vi debaixo do sol: riquezas foram guardadas por seu dono para o seu próprio dano;");
    b->dados[ECLESIASTES].capitulos[5].versos[14] = _("e as mesmas riquezas se perderam por qualquer má aventura; e havendo algum filho nada fica na sua mão.");
    b->dados[ECLESIASTES].capitulos[5].versos[15] = _("Como saiu do ventre de sua mãe, assim também se irá, nu como veio; e nada tomará do seu trabalho, que possa levar na mão.");
    b->dados[ECLESIASTES].capitulos[5].versos[16] = _("Ora isso é um grave mal; porque justamente como veio, assim há de ir; e que proveito lhe vem de ter trabalhado para o vento,");
    b->dados[ECLESIASTES].capitulos[5].versos[17] = _("e de haver passado todos os seus dias nas trevas, e de haver padecido muito enfado, enfermidades e aborrecimento?");
    b->dados[ECLESIASTES].capitulos[5].versos[18] = _("Eis aqui o que eu vi, uma boa e bela coisa: alguém comer e beber, e gozar cada um do bem de todo o seu trabalho, com que se afadiga debaixo do sol, todos os dias da vida que Deus lhe deu; pois esse é o seu quinhão.");
    b->dados[ECLESIASTES].capitulos[5].versos[19] = _("E quanto ao homem a quem Deus deu riquezas e bens, e poder para desfrutá-los, receber o seu quinhão, e se regozijar no seu trabalho, isso é dom de Deus.");
    b->dados[ECLESIASTES].capitulos[5].versos[20] = _("Pois não se lembrará muito dos dias da sua vida; porque Deus lhe enche de alegria o coração.");

    b->dados[ECLESIASTES].capitulos[6].versos[1] = _("Há um mal que tenho visto debaixo do sol, e que pesa muito sobre o homem:");
    b->dados[ECLESIASTES].capitulos[6].versos[2] = _("um homem a quem Deus deu riquezas, bens e honra, de maneira que nada lhe falta de tudo quanto ele deseja, contudo Deus não lhe dá poder para daí comer, antes o estranho lho come; também isso é vaidade e grande mal.");
    b->dados[ECLESIASTES].capitulos[6].versos[3] = _("Se o homem gerar cem filhos, e viver muitos anos, de modo que os dias da sua vida sejam muitos, porém se a sua alma não se fartar do bem, e além disso não tiver sepultura, digo que um aborto é melhor do que ele;");
    b->dados[ECLESIASTES].capitulos[6].versos[4] = _("porquanto debalde veio, e em trevas se vai, e de trevas se cobre o seu nome;");
    b->dados[ECLESIASTES].capitulos[6].versos[5] = _("e ainda que nunca viu o sol, nem o conheceu, mais descanso tem do que o tal;");
    b->dados[ECLESIASTES].capitulos[6].versos[6] = _("e embora vivesse duas vezes mil anos, mas não gozasse o bem. Não vão todos para um mesmo lugar?");
    b->dados[ECLESIASTES].capitulos[6].versos[7] = _("Todo o trabalho do homem é para a sua boca, e contudo não se satisfaz o seu apetite.");
    b->dados[ECLESIASTES].capitulos[6].versos[8] = _("Pois, que vantagem tem o sábio sobre o tolo? e que tem o pobre que sabe andar perante os vivos?");
    b->dados[ECLESIASTES].capitulos[6].versos[9] = _("Melhor é a vista dos olhos do que o vaguear da cobiça; também isso é vaidade, e desejo vão.");
    b->dados[ECLESIASTES].capitulos[6].versos[10] = _("Seja qualquer o que for, já há muito foi chamado pelo seu nome; e sabe-se que é homem; e ele não pode contender com o que é mais forte do que ele.");
    b->dados[ECLESIASTES].capitulos[6].versos[11] = _("Visto que as muitas palavras aumentam a vaidade, que vantagem tira delas o homem?");
    b->dados[ECLESIASTES].capitulos[6].versos[12] = _("Porque, quem sabe o que é bom nesta vida para o homem, durante os poucos dias da sua vida vã, os quais gasta como sombra? pois quem declarará ao homem o que será depois dele debaixo do sol?");

    b->dados[ECLESIASTES].capitulos[7].versos[1] = _("Melhor é o bom nome do que o melhor ungüento, e o dia da morte do que o dia do nascimento.");
    b->dados[ECLESIASTES].capitulos[7].versos[2] = _("Melhor é ir à casa onde há luto do que ir a casa onde há banquete; porque naquela se vê o fim de todos os homens, e os vivos o aplicam ao seu coração.");
    b->dados[ECLESIASTES].capitulos[7].versos[3] = _("Melhor é a mágoa do que o riso, porque a tristeza do rosto torna melhor o coração.");
    b->dados[ECLESIASTES].capitulos[7].versos[4] = _("O coração dos sábios está na casa do luto, mas o coração dos tolos na casa da alegria.");
    b->dados[ECLESIASTES].capitulos[7].versos[5] = _("Melhor é ouvir a repreensão do sábio do que ouvir alguém a canção dos tolos.");
    b->dados[ECLESIASTES].capitulos[7].versos[6] = _("Pois qual o crepitar dos espinhos debaixo da panela, tal é o riso do tolo; também isso é vaidade.");
    b->dados[ECLESIASTES].capitulos[7].versos[7] = _("Verdadeiramente a opressão faz endoidecer até o sábio, e a peita corrompe o coração.");
    b->dados[ECLESIASTES].capitulos[7].versos[8] = _("Melhor é o fim duma coisa do que o princípio; melhor é o paciente do que o arrogante.");
    b->dados[ECLESIASTES].capitulos[7].versos[9] = _("Não te apresses no teu espírito a irar-te, porque a ira abriga-se no seio dos tolos.");
    b->dados[ECLESIASTES].capitulos[7].versos[10] = _("Não digas: Por que razão foram os dias passados melhores do que estes; porque não provém da sabedoria esta pergunta.");
    b->dados[ECLESIASTES].capitulos[7].versos[11] = _("Tão boa é a sabedoria como a herança, e mesmo de mais proveito para os que vêem o sol.");
    b->dados[ECLESIASTES].capitulos[7].versos[12] = _("Porque a sabedoria serve de defesa, como de defesa serve o dinheiro; mas a excelência da sabedoria é que ela preserva a vida de quem a possui.");
    b->dados[ECLESIASTES].capitulos[7].versos[13] = _("Considera as obras de Deus; porque quem poderá endireitar o que ele fez torto?");
    b->dados[ECLESIASTES].capitulos[7].versos[14] = _("No dia da prosperidade regozija-te, mas no dia da adversidade considera; porque Deus fez tanto este como aquele, para que o homem nada descubra do que há de vir depois dele.");
    b->dados[ECLESIASTES].capitulos[7].versos[15] = _("Tudo isto vi nos dias da minha vaidade: há justo que perece na sua justiça, e há ímpio que prolonga os seus dias na sua maldade.");
    b->dados[ECLESIASTES].capitulos[7].versos[16] = _("Não sejas demasiadamente justo, nem demasiadamente sábio; por que te destruirias a ti mesmo?");
    b->dados[ECLESIASTES].capitulos[7].versos[17] = _("Não sejas demasiadamente ímpio, nem sejas tolo; por que morrerias antes do teu tempo?");
    b->dados[ECLESIASTES].capitulos[7].versos[18] = _("Bom é que retenhas isso, e que também daquilo não retires a tua mão; porque quem teme a Deus escapa de tudo isso.");
    b->dados[ECLESIASTES].capitulos[7].versos[19] = _("A sabedoria fortalece ao sábio mais do que dez governadores que haja na cidade.");
    b->dados[ECLESIASTES].capitulos[7].versos[20] = _("Pois não há homem justo sobre a terra, que faça o bem, e nunca peque.");
    b->dados[ECLESIASTES].capitulos[7].versos[21] = _("Não escutes a todas as palavras que se disserem, para que não venhas a ouvir o teu servo amaldiçoar-te;");
    b->dados[ECLESIASTES].capitulos[7].versos[22] = _("pois tu sabes também que muitas vezes tu amaldiçoaste a outros.");
    b->dados[ECLESIASTES].capitulos[7].versos[23] = _("Tudo isto provei-o pela sabedoria; e disse: Far-me-ei sábio; porém a sabedoria ainda ficou longe de mim.");
    b->dados[ECLESIASTES].capitulos[7].versos[24] = _("Longe está o que já se foi, e profundíssimo; quem o poderá achar?");
    b->dados[ECLESIASTES].capitulos[7].versos[25] = _("Eu me volvi, e apliquei o meu coração para saber, e inquirir, e buscar a sabedoria e a razão de tudo, e para conhecer que a impiedade é insensatez e que a estultícia é loucura.");
    b->dados[ECLESIASTES].capitulos[7].versos[26] = _("E eu achei uma coisa mais amarga do que a morte, a mulher cujo coração são laços e redes, e cujas mãos são grilhões; quem agradar a Deus escapará dela; mas o pecador virá a ser preso por ela.");
    b->dados[ECLESIASTES].capitulos[7].versos[27] = _("Vedes aqui, isto achei, diz o pregador, conferindo uma coisa com a outra para achar a causa;");
    b->dados[ECLESIASTES].capitulos[7].versos[28] = _("causa que ainda busco, mas não a achei; um homem entre mil achei eu, mas uma mulher entre todas, essa não achei.");
    b->dados[ECLESIASTES].capitulos[7].versos[29] = _("Eis que isto tão-somente achei: que Deus fez o homem reto, mas os homens buscaram muitos artifícios.");

    b->dados[ECLESIASTES].capitulos[8].versos[1] = _("Quem é como o sábio? e quem sabe a interpretação das coisas? A sabedoria do homem faz brilhar o seu rosto, e com ela a dureza do seu rosto se transforma.");
    b->dados[ECLESIASTES].capitulos[8].versos[2] = _("Eu digo: Observa o mandamento do rei, e isso por causa do juramento a Deus.");
    b->dados[ECLESIASTES].capitulos[8].versos[3] = _("Não te apresses a sair da presença dele; nem persistas em alguma coisa má; porque ele faz tudo o que lhe agrada.");
    b->dados[ECLESIASTES].capitulos[8].versos[4] = _("Porque a palavra do rei é suprema; e quem lhe dirá: que fazes?");
    b->dados[ECLESIASTES].capitulos[8].versos[5] = _("Quem guardar o mandamento não experimentará nenhum mal; e o coração do sábio discernirá o tempo e o juízo.");
    b->dados[ECLESIASTES].capitulos[8].versos[6] = _("Porque para todo propósito há tempo e juízo; porquanto a miséria do homem pesa sobre ele.");
    b->dados[ECLESIASTES].capitulos[8].versos[7] = _("Porque não sabe o que há de suceder; pois quem lho dará a entender como há de ser?");
    b->dados[ECLESIASTES].capitulos[8].versos[8] = _("Nenhum homem há que tenha domínio sobre o espírito, para o reter; nem que tenha poder sobre o dia da morte; nem há licença em tempo de guerra; nem tampouco a impiedade livrará aquele que a ela está entregue.");
    b->dados[ECLESIASTES].capitulos[8].versos[9] = _("Tudo isto tenho observado enquanto aplicava o meu coração a toda obra que se faz debaixo do sol; tempo há em que um homem tem domínio sobre outro homem para o seu próprio dano.");
    b->dados[ECLESIASTES].capitulos[8].versos[10] = _("Vi também os ímpios sepultados, os que antes entravam e saíam do lugar santo; e foram esquecidos na cidade onde haviam assim procedido; também isso é vaidade.");
    b->dados[ECLESIASTES].capitulos[8].versos[11] = _("Porquanto não se executa logo o juízo sobre a má obra, o coração dos filhos dos homens está inteiramente disposto para praticar o mal.");
    b->dados[ECLESIASTES].capitulos[8].versos[12] = _("Ainda que o pecador faça o mal cem vezes, e os dias se lhe prolonguem, contudo eu sei com certeza que bem sucede aos que temem a Deus, porque temem diante dele;");
    b->dados[ECLESIASTES].capitulos[8].versos[13] = _("ao ímpio, porém, não irá bem, e ele não prolongará os seus dias, que são como a sombra; porque ele não teme diante de Deus.");
    b->dados[ECLESIASTES].capitulos[8].versos[14] = _("Ainda há outra vaidade que se faz sobre a terra: há justos a quem sucede segundo as obras dos ímpios, e há ímpios a quem sucede segundo as obras dos justos. Eu disse que também isso é vaidade.");
    b->dados[ECLESIASTES].capitulos[8].versos[15] = _("Exalto, pois, a alegria, porquanto o homem nenhuma coisa melhor tem debaixo do sol do que comer, beber e alegrar-se; porque isso o acompanhará no seu trabalho nos dias da sua vida que Deus lhe dá debaixo do sol.");
    b->dados[ECLESIASTES].capitulos[8].versos[16] = _("Quando apliquei o meu coração a conhecer a sabedoria, e a ver o trabalho que se faz sobre a terra {pois homens há que nem de dia nem de noite conseguem dar sono aos seus olhos},");
    b->dados[ECLESIASTES].capitulos[8].versos[17] = _("então contemplei toda obra de Deus, e vi que o homem não pode compreender a obra que se faz debaixo do sol; pois por mais que o homem trabalhe para a descobrir, não a achará; embora o sábio queira conhecê-la, nem por isso a poderá compreender.");

    b->dados[ECLESIASTES].capitulos[9].versos[1] = _("Deveras a tudo isto apliquei o meu coração, para claramente entender tudo isto: que os justos, e os sábios, e as suas obras, estão nas mãos de Deus; se é amor ou se é ódio, não o sabe o homem; tudo passa perante a sua face.");
    b->dados[ECLESIASTES].capitulos[9].versos[2] = _("Tudo sucede igualmente a todos: o mesmo sucede ao justo e ao ímpio, ao bom e ao mau, ao puro e ao impuro; assim ao que sacrifica como ao que não sacrifica; assim ao bom como ao pecador; ao que jura como ao que teme o juramento.");
    b->dados[ECLESIASTES].capitulos[9].versos[3] = _("Este é o mal que há em tudo quanto se faz debaixo do sol: que a todos sucede o mesmo. Também o coração dos filhos dos homens está cheio de maldade; há desvarios no seu coração durante a sua vida, e depois se vão aos mortos.");
    b->dados[ECLESIASTES].capitulos[9].versos[4] = _("Ora, para aquele que está na companhia dos vivos há esperança; porque melhor é o cão vivo do que o leão morto.");
    b->dados[ECLESIASTES].capitulos[9].versos[5] = _("Pois os vivos sabem que morrerão, mas os mortos não sabem coisa nenhuma, nem tampouco têm eles daí em diante recompensa; porque a sua memória ficou entregue ao esquecimento.");
    b->dados[ECLESIASTES].capitulos[9].versos[6] = _("Tanto o seu amor como o seu ódio e a sua inveja já pereceram; nem têm eles daí em diante parte para sempre em coisa alguma do que se faz debaixo do sol.");
    b->dados[ECLESIASTES].capitulos[9].versos[7] = _("Vai, pois, come com alegria o teu pão .e bebe o teu vinho com coração contente; pois há muito que Deus se agrada das tuas obras.");
    b->dados[ECLESIASTES].capitulos[9].versos[8] = _("Sejam sempre alvas as tuas vestes, e nunca falte o óleo sobre a tua cabeça.");
    b->dados[ECLESIASTES].capitulos[9].versos[9] = _("Goza a vida com a mulher que amas, todos os dias da tua vida vã, os quais Deus te deu debaixo do sol, todos os dias da tua vida vã; porque este é o teu quinhão nesta vida, e do teu trabalho, que tu fazes debaixo do sol.");
    b->dados[ECLESIASTES].capitulos[9].versos[10] = _("Tudo quanto te vier à mão para fazer, faze-o conforme as tuas forças; porque no Seol, para onde tu vais, não há obra, nem projeto, nem conhecimento, nem sabedoria alguma.");
    b->dados[ECLESIASTES].capitulos[9].versos[11] = _("Observei ainda e vi que debaixo do sol não é dos ligeiros a carreira, nem dos fortes a peleja, nem tampouco dos sábios o pão, nem ainda dos prudentes a riqueza, nem dos entendidos o favor; mas que a ocasião e a sorte ocorrem a todos.");
    b->dados[ECLESIASTES].capitulos[9].versos[12] = _("Pois o homem não conhece a sua hora. Como os peixes que se apanham com a rede maligna, e como os passarinhos que se prendem com o laço, assim se enlaçam também os filhos dos homens no mau tempo, quando este lhes sobrevém de repente.");
    b->dados[ECLESIASTES].capitulos[9].versos[13] = _("Também vi este exemplo de sabedoria debaixo do sol, que me pareceu grande:");
    b->dados[ECLESIASTES].capitulos[9].versos[14] = _("Houve uma pequena cidade em que havia poucos homens; e veio contra ela um grande rei, e a cercou e levantou contra ela grandes tranqueiras.");
    b->dados[ECLESIASTES].capitulos[9].versos[15] = _("Ora, achou-se nela um sábio pobre, que livrou a cidade pela sua sabedoria; contudo ninguém se lembrou mais daquele homem pobre.");
    b->dados[ECLESIASTES].capitulos[9].versos[16] = _("Então disse eu: Melhor é a sabedoria do que a força; todavia a sabedoria do pobre é desprezada, e as suas palavras não são ouvidas.");
    b->dados[ECLESIASTES].capitulos[9].versos[17] = _("As palavras dos sábios ouvidas em silêncio valem mais do que o clamor de quem governa entre os tolos.");
    b->dados[ECLESIASTES].capitulos[9].versos[18] = _("Melhor é a sabedoria do que as armas de guerra; mas um só pecador faz grande dano ao bem.");

    b->dados[ECLESIASTES].capitulos[10].versos[1] = _("As moscas mortas fazem com que o ungüento do perfumista emita mau cheiro; assim um pouco de estultícia pesa mais do que a sabedoria e a honra.");
    b->dados[ECLESIASTES].capitulos[10].versos[2] = _("O coração do sábio o inclina para a direita, mas o coração do tolo o inclina para a esquerda.");
    b->dados[ECLESIASTES].capitulos[10].versos[3] = _("E, até quando o tolo vai pelo caminho, falta-lhe o entendimento, e ele diz a todos que é tolo.");
    b->dados[ECLESIASTES].capitulos[10].versos[4] = _("Se levantar contra ti o espírito do governador, não deixes o teu lugar; porque a deferência desfaz grandes ofensas.");
    b->dados[ECLESIASTES].capitulos[10].versos[5] = _("Há um mal que vi debaixo do sol, semelhante a um erro que procede do governador:");
    b->dados[ECLESIASTES].capitulos[10].versos[6] = _("a estultícia está posta em grande dignidade, e os ricos estão assentados em lugar humilde.");
    b->dados[ECLESIASTES].capitulos[10].versos[7] = _("Tenho visto servos montados a cavalo, e príncipes andando a pé como servos.");
    b->dados[ECLESIASTES].capitulos[10].versos[8] = _("Aquele que abrir uma cova, nela cairá; e quem romper um muro, uma cobra o morderá.");
    b->dados[ECLESIASTES].capitulos[10].versos[9] = _("Aquele que tira pedras é maltratado por elas, e o que racha lenha corre perigo nisso.");
    b->dados[ECLESIASTES].capitulos[10].versos[10] = _("Se estiver embotado o ferro, e não se afiar o corte, então se deve pôr mais força; mas a sabedoria é proveitosa para dar prosperidade.");
    b->dados[ECLESIASTES].capitulos[10].versos[11] = _("Se a cobra morder antes de estar encantada, não há vantagem no encantador.");
    b->dados[ECLESIASTES].capitulos[10].versos[12] = _("As palavras da boca do sábio são cheias de graça, mas os lábios do tolo o devoram.");
    b->dados[ECLESIASTES].capitulos[10].versos[13] = _("O princípio das palavras da sua boca é estultícia, e o fim do seu discurso é loucura perversa.");
    b->dados[ECLESIASTES].capitulos[10].versos[14] = _("O tolo multiplica as palavras, todavia nenhum homem sabe o que há de ser; e quem lhe poderá declarar o que será depois dele?");
    b->dados[ECLESIASTES].capitulos[10].versos[15] = _("O trabalho do tolo o fatiga, de sorte que não sabe ir à cidade.");
    b->dados[ECLESIASTES].capitulos[10].versos[16] = _("Ai de ti, ó terra, quando o teu rei é criança, e quando os teus príncipes banqueteiam de manhã!");
    b->dados[ECLESIASTES].capitulos[10].versos[17] = _("Bem-aventurada tu, ó terra, quando o teu rei é filho de nobres, e quando os teus príncipes comem a tempo, para refazerem as forças, e não para bebedice!");
    b->dados[ECLESIASTES].capitulos[10].versos[18] = _("Pela preguiça se enfraquece o teto, e pela frouxidão das mãos a casa tem goteiras.");
    b->dados[ECLESIASTES].capitulos[10].versos[19] = _("Para rir é que se dá banquete, e o vinho alegra a vida; e por tudo o dinheiro responde.");
    b->dados[ECLESIASTES].capitulos[10].versos[20] = _("Nem ainda no teu pensamento amaldições o rei; nem tampouco na tua recâmara amaldiçoes o rico; porque as aves dos céus levarão a voz, e uma criatura alada dará notícia da palavra.");

    b->dados[ECLESIASTES].capitulos[11].versos[1] = _("Lança o teu pão sobre as águas, porque depois de muitos dias o acharás.");
    b->dados[ECLESIASTES].capitulos[11].versos[2] = _("Reparte com sete, e ainda até com oito; porque não sabes que mal haverá sobre a terra.");
    b->dados[ECLESIASTES].capitulos[11].versos[3] = _("Estando as nuvens cheias de chuva, derramam-na sobre a terra. Caindo a árvore para o sul, ou para o norte, no lugar em que a árvore cair, ali ficará.");
    b->dados[ECLESIASTES].capitulos[11].versos[4] = _("Quem observa o vento, não semeará, e o que atenta para as nuvens não segará.");
    b->dados[ECLESIASTES].capitulos[11].versos[5] = _("Assim como tu não sabes qual o caminho do vento, nem como se formam os ossos no ventre da que está grávida, assim também não sabes as obras de Deus, que faz todas as coisas.");
    b->dados[ECLESIASTES].capitulos[11].versos[6] = _("Pela manhã semeia a tua semente, e à tarde não retenhas a tua mão; pois tu não sabes qual das duas prosperará, se esta, se aquela, ou se ambas serão, igualmente boas.");
    b->dados[ECLESIASTES].capitulos[11].versos[7] = _("Doce é a luz, e agradável é aos olhos ver o sol.");
    b->dados[ECLESIASTES].capitulos[11].versos[8] = _("Se, pois, o homem viver muitos anos, regozije-se em todos eles; contudo lembre-se dos dias das trevas, porque hão de ser muitos. Tudo quanto sucede é vaidade.");
    b->dados[ECLESIASTES].capitulos[11].versos[9] = _("Alegra-te, mancebo, na tua mocidade, e anime-te o teu coração nos dias da tua mocidade, e anda pelos caminhos do teu coração, e pela vista dos teus olhos; sabe, porém, que por todas estas coisas Deus te trará a juízo.");
    b->dados[ECLESIASTES].capitulos[11].versos[10] = _("Afasta, pois, do teu coração o desgosto, remove da tua carne o mal; porque a mocidade e a aurora da vida são vaidade.");

    b->dados[ECLESIASTES].capitulos[12].versos[1] = _("Lembra-te também do teu Criador nos dias da tua mocidade, antes que venham os maus dias, e cheguem os anos em que dirás: Não tenho prazer neles;");
    b->dados[ECLESIASTES].capitulos[12].versos[2] = _("antes que se escureçam o sol e a luz, e a lua, e as estrelas, e tornem a vir as nuvens depois da chuva;");
    b->dados[ECLESIASTES].capitulos[12].versos[3] = _("no dia em que tremerem os guardas da casa, e se curvarem os homens fortes, e cessarem os moedores, por já serem poucos, e se escurecerem os que olham pelas janelas,");
    b->dados[ECLESIASTES].capitulos[12].versos[4] = _("e as portas da rua se fecharem; quando for baixo o ruído da moedura, e nos levantarmos à voz das aves, e todas as filhas da música ficarem abatidas;");
    b->dados[ECLESIASTES].capitulos[12].versos[5] = _("como também quando temerem o que é alto, e houver espantos no caminho; e florescer a amendoeira, e o gafanhoto for um peso, e falhar o desejo; porque o homem se vai à sua casa eterna, e os pranteadores andarão rodeando pela praça;");
    b->dados[ECLESIASTES].capitulos[12].versos[6] = _("antes que se rompa a cadeia de prata, ou se quebre o copo de ouro, ou se despedace o cântaro junto à fonte, ou se desfaça a roda junto à cisterna,");
    b->dados[ECLESIASTES].capitulos[12].versos[7] = _("e o pó volte para a terra como o era, e o espírito volte a Deus que o deu.");
    b->dados[ECLESIASTES].capitulos[12].versos[8] = _("Vaidade de vaidades, diz o pregador, tudo é vaidade.");
    b->dados[ECLESIASTES].capitulos[12].versos[9] = _("Além de ser sábio, o pregador também ensinou ao povo o conhecimento, meditando, e estudando, e pondo em ordem muitos provérbios.");
    b->dados[ECLESIASTES].capitulos[12].versos[10] = _("Procurou o pregador achar palavras agradáveis, e escreveu com acerto discursos plenos de verdade.");
    b->dados[ECLESIASTES].capitulos[12].versos[11] = _("As palavras dos sábios são como aguilhões; e como pregos bem fixados são as palavras coligidas dos mestres, as quais foram dadas pelo único pastor.");
    b->dados[ECLESIASTES].capitulos[12].versos[12] = _("Além disso, filho meu, sê avisado. De fazer muitos livros não há fim; e o muito estudar é enfado da carne.");
    b->dados[ECLESIASTES].capitulos[12].versos[13] = _("Este é o fim do discurso; tudo já foi ouvido: Teme a Deus, e guarda os seus mandamentos; porque isto é todo o dever do homem.");
    b->dados[ECLESIASTES].capitulos[12].versos[14] = _("Porque Deus há de trazer a juízo toda obra, e até tudo o que está encoberto, quer seja bom, quer seja mau.");

}
